#!/usr/bin/perl

use strict;
use warnings;

if (@ARGV != 1) {
    die "Usage: $0 <filename>\n";
}

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Could not open file '$filename': $!";

my %word_counts;

while (my $line = <$fh>) {
    chomp $line;
    foreach my $word (split /\s+/, $line) {
        lc($word);
        $word_counts{$word}++;
    }
}

close $fh;

my @sorted_words;
while (%word_counts){
  k = shift keys %word_counts;
  push @sorted_words, ($k, $word_counts{$k});
}

for (my $i=0;$i<3;++$i){
    if (@sorted_words) {
        print "$sorted_words[$i]{0}: $sorted_words[$i]{1}\n";
    } else {
        print "No words found.\n";
        break;
    }
}

#!/usr/bin/perl

use strict;
use warnings;

if (@ARGV != 1) {
    die "Usage: $0 <filename>\n";
}

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Could not open file '$filename': $!";

while (my $line = <$fh>) {
    chomp($line);
    my @fields = split(',', $line);

    if (@fields == 3 && $fields[1] > 30) {
        print "$line\n";
    }
}

close($fh);

#!/usr/bin/perl

use strict;
use warnings;

if ($#ARGV != 1) {
    die "Usage: $0 <filename>\n";
}

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Could not open file '$filename': $!";

while (my $line = <$fh>) {
    # Regular expression to match email addresses
    if ($line =~ /[\w\.-]+@[\w\.-]+\./) {
        print "$1\n" if $line =~ m/([\w\.-]+@[\w\.-]+)/;
    }
}

close($fh);
